postToolUse.powershell:
$mode = if ($env:VSTACK_HOOKS_MODE) { $env:VSTACK_HOOKS_MODE } else { 'audit' }
if ($mode -ne 'enforce') {
  exit 0
}
$inputText = [Console]::In.ReadToEnd()
function Write-HookLog {
  param([string]$Message)
  $logName = if ($env:VSTACK_HOOK_LOG_NAME) { $env:VSTACK_HOOK_LOG_NAME } else { 'hook-markdown-quality-alerts.log' }
  $logRoot = if ($env:VSTACK_HOOK_LOG_DIR) { $env:VSTACK_HOOK_LOG_DIR } else { '.vstack/logs' }
  $logDir = Join-Path $logRoot (Get-Date).ToUniversalTime().ToString('yyyyMMdd')
  New-Item -ItemType Directory -Force -Path $logDir | Out-Null
  Add-Content -Path (Join-Path $logDir $logName) -Value $Message
}
if ($inputText -notmatch '\.md|docs/|\.github/|\.vstack/templates/|adr/|prompt\.md|instructions\.md|SKILL\.md') {
  exit 0
}
if ((Test-Path Makefile) -and (Get-Command make -ErrorAction SilentlyContinue)) {
  make markdown-format *> $null
  if ($LASTEXITCODE -ne 0) {
    make format *> $null
  }
  if ($LASTEXITCODE -ne 0) {
    Write-HookLog 'markdown-format-run-failed'
  }
} else {
   Write-HookLog 'markdown-format-skipped-missing-make-or-makefile'
}
